INSERT INTO topics (id, lang, category, title, question, answer, objections, scripture, tags, difficulty, related_topics, translation_source, last_updated)
VALUES ('divinity-of-christ', 'ceb', 'church-teaching', 'Pagka-Dios ni Cristo', 'Unsa ang gitudlo sa Simbahang Katoliko bahin sa pagka-dios ni cristo?', '"Ang Sta. Iglesya nagtudlo nga si Cristo mao ang ikaduhang Persona sa Santisima Trinidad. Siya usa ka pagka-Dios sa Amahan. Siya ang Pulong sa Dios, ang bugtong Anak sa Dios. Sugod sa iyang pagpakatawo si Cristo naghupot sa duha ka kinaiya: siya matuod nga Dios ug matuod nga tawo. Ang iyang pagka-Dios naggikan sa Amahan sukad sa walay sinugdan ug ang iyang pagkatawo gikan ni Sta. Maria. Bisan kon ang pagka-Dios ug ang pagka-tawo nahiusa diha ni Cristo apan wala usab kini magkasambog. Busa maingon nato nga si Cristo gikapoy, nag-antos, misinati sa kamatayon diha sa iyang pagka-tawo apan sa iyang pagka-Dios dili siya kapuyon, mag-antos o mamatay apan tungod kay si Cristo usa man ka diosnong persona ang tanan niyang gihimo pinaagi sa iyang tawhanong kinaiya gihimo kini sa usa diosnong persona busa duna kini walay kinutuban nga bili. Ang tanan nga gihimo ni Cristo pinaagi sa iyang diosnong kinaiya iyang kining gihimo uban sa Amahan ug sa Espiritu Santo apan unsay iyang gihimo pinaagi sa iyang tawhanon nga kinaiya maisip nato nga iya ra kini ni Cristo. Tungod kay si Cristo naghupot man sa duha ka kinaiya: pagka-Dios ug pagka-tawo duna siyay Diosnong salabutan ug tawhanong nga salabutan ug duna siyay Diosnong kabubut-on ug tawhanong kabubut-on. Ang iyang tawhanong salabutan kanunay nga gilamdagan sa Diosnong kaalam ug ang iyang tawhanong kabubut-on kanunay nga nagtuman sa Diosnong pagbuot.\n\nAng Biblia nagpamatuod gayod sa pagka-Dios ni Cristo. Mahitungod sa Mesiyas gitagna, “Kay natawo alang kanato ang usa ka bata, gihatag kanato ang usa ka anak lalaki; ug siya ang magmando sa tanan, ug nganlan siyag, “Maalamong Magtatambag, Dios nga Gamhanan, Walay Kataposang Amahan, Prinsipe sa Pakigdait” (Isa. 9:6). Ang katumanan niini mao si Cristo, “Kay karong gabhiona, natawo sa lungsod ni David ang inyong Manluluwas, ang Cristo nga Ginoo” (Luc. 2:11) ug sumala sa tagna siya Dios nga gamhanan. Si Isaias nagsulat usab, “Ingna ang nakabsan nag paglaom, ‘Pagmaisog ug ayaw kahadlok! Moanha ang imong Dios aron sa pagpanimalos sa imong mga kaaway.’ Makakita na unya ang buta ug makadungog na ang bungol; magluksolukso na ang bakol daw lagsaw” (Isa. 35:4-6). Sa dihang si Jesus gipangutana sa mga tinun-an ni Juan kon siya ba ang gipaabot nga moanhi si Jesus miingon kanila, “Pamauli kamo ug suginli si Juan sa inyong nadungog ug nakita: ang mga buta nakakita, ang mga bakol nakalakaw, ang mga sanlahon nangaayo, ang mga bungol nakadungog, ang mga minatay nangabanhaw” (Mat. 11:4-5). Busa si Jesus tin-aw nga nagpasabot nga siya ang katumanan sa Dios nga moanhi ug ang timaan sa iyang pag-abot mao ang daghang mga milagro nga iyang himoon. Sa laing bahin sa sinulat ni Isaias mabasa, “kay mag-una kaninyo ang Ginoo, ug ang Dios sa Israel maoy magbantay sa inyong luyo” (Isa. 52:12). Ug kining Dios sa Israel nga magpaluyo kanila mao si Cristo, “kay nanginom man sila gikan sa espirituhanong bato nga nagpaluyo kanila, ug kadtong batoha mao si Cristo” (1 Cor. 10:4).\nSa unang kapitulo sa ebanghelyo ni San Juan atong mabasa, “Sa wala pay nabuhat bisan unsa, ang Pulong diha na” (v. 1)- nagpasabot kini nga ang Pulong dili binuhat kay diha na man siya sa wala pay nabuhat bisan unsa. “Ang Pulong uban sa Dios” (v. 1)- nagtug-an kini nga ang Pulong lahi sa pagka-persona sa Dios nga referido sa Amahan. “ug ang Pulong Dios” (v. 1)- dinhi giklaro ni Juan ang kinaiya kun “nature” o “substance” sa Pulong nga siya Dios. “Sukad pa gayod sa sinugdan ang Pulong uban sa Dios” (v. 2)- gisubli dinhi ni San Juan ang iyang gisulti sa unahan aron pagpahimug-at sa nga bisan kon ang Pulong Dios lahi siya nga pagka-persona sa Amahan. “Pinaagi kaniya gibuhat sa Dios ang tanan, ug walay usa sa tanan nga nabuhat nga dili pinaagi kaniya” (v. 3)- kini nagtudlo kanato nga ang Pulong kauban sa Amahan diha sa pagpamuhat sa tanang butang; bulohaton nga mahimo lamang sa Dios. “Gikan kaniya (referido sa Pulong) ang kinabuhi, ug ang maong kinabuhi mao ang kahayag sa mga tawo” (v. 4)- dinhi gipahimug-atan na usab ang pagka-Dios sa Pulong tungod kay ang Dios ra man ang tinubdan sa tanang kinabuhi ug kahayag sa tawo (Sal. 36:9). “Ang Pulong nahimong tawo ug mipuyo uban kanato. Nakita namo ang iyang himaya nga puno sa grasya ug sa kamatuoran. Kini ang himaya nga iyang nadawat ingon nga bugtong Anak sa Amahan” (v. 14). Dinhi gipasabot ang misteryo sa incarnation kun pagpakatawo sa Pulong: 1) Nga ang Pulong nga kauban sa Amahan sa wala pay nabuhat bisan unsa mao ang iyang bugtong Anak, 2) Nga ang Pulong nga naglihok kaniadto sa dili makita nga paagi karon napadayag diha sa iyang pagpakatawo, diha sa Persona ni Jesu-Cristo. Mao kini ang tema nga kanunay nga hisgotan sa ebanghelista. Iyang gipakita nga si Jesus bisan kon nakita ingon nga tawo apan nagpasabot nga siya Dios. “Ang tanan nga gibuhat sa Amahan, gibuhat usab sa Anak” (Jn. 5:19). “Kamo taga dinhi sa yuta, apan ako gikan sa langit” (Jn. 8:23). “Sultihan ko kamo: wala pa gani matawo si Abraham, Ako mao na” (Jn. 8:58). “Ang akong Amahan ug ako usa ra” (Jn. 10:30). “Karon, Amahan, himayaa ako diha sa himaya nga gihuptan ko kauban nimo sa wala pa buhata ang kalibotan” (Jn. 17:5). Sa pagkabanhaw ni Jesus, si Tomas mipahayag sa pagtuo sa Simbahan mahitungod kang Jesus, “Ginoo ko ug Dios ko” (Jn. 20:28). “Ang atong kinabuhi anaa sa matuod nga Dios- sa iyang Anak nga si Jesu-Cristo. Siya ang matuod nga Dios ug ang kinabuhi nga walay kataposan” (1 Jn. 5:20).\nSi San Pablo diha sa iyang mga sulat nagtudlo usab niini nga kamatuoran. “Kaliwat sila sa mga patriarka, ug sa ilang kaliwatan natawo si Cristo ang Dios nga labaw sa tanan daygon unta hangtod sa kahangtoran” (Rom. 9:5); “samtang nagpaabot kita sa bulahang Adlaw nga atong gilaoman inigpadayag na sa himaya sa atong gamhanang Dios ug Manluluwas nga si Jesu-Cristo” (Tito 2:13); “Diha niya kanunay ang kinaiya gayod sa Dios, apan wala siya maghunahuna pagpakigtupong sa Dios pinaagi sa kusog… Busa mangluhod ang tanang binuhat sa langit, sa yuta ug sa ilalom sa yuta; sa pagpasidungog sa ngalan ni Jesus” (Fil. 2:6, 10). “Kay ang tibuok nga kinaiya sa Dios anaa kang Cristo sa iyang pagkatawo” (Col. 2:9). Apan bahin sa iyang Anak, miingon ang Dios (Amahan), “Ang imong trono, O Dios, molungtad hangtod sa kahangtoran” (Heb. 1:8)."'::jsonb, '[{"objection":"Ang Biblia nagtudlo kanato nga usa lamang ang Dios, “Ako mao ang Ginoo, wala nay lain, walay Dios gawas kanako” (Isa. 45:5). Ang bugtong Dios nga gipaila ni Jesus mao ang Amahan, “Ug kini ang kinabuhing dayon: nga ang mga tawo moila kanimo (Amahan), ang bugtong matuod nga Dios, ug kang Jesu-Cristo nga imong gipadala” (Jn. 17:3). Si San Pablo nagtudlo, “apan alang kanato may usa lamang ka Dios, ang Amahan” (1 Cor. 8:6). Kon si Cristo Dios mogawas nga duha na ang Dios.","response":"Si Cristo dili lain nga pagka-Dios sa Amahan kay siya miingon, “Ako ug ang Amahan usa ra” (Jn. 10:30). Dili sabton nga kon si Cristo mipaila sa Amahan nga Dios nga dili na siya Dios tungod kay ang Amahan mitawag usab sa Anak nga Dios, “Ang imong trono, O Dios, molungtad hangtod sa kahangtoran” (Heb. 1:8) wala kini magpasabot nga dili na Dios ang Amahan."},{"objection":"“Ang Dios dili tawo… dili anak sa tawo” (Num 23:19). Apan si Cristo tawo, “Wala nay laing manlalaban taliwala sa Dios ug sa tawo, si Cristo nga tawo” (1 Tim. 2:5) ug si Cristo gianak og tawo, “pag-abot sa hustong panahon gipadala sa Dios ang iyang bugtong anak ug natawo sa tawhanong inahan” (Gal. 4:4) busa dili siya Dios.","response":"Maoy gipaila dinhi ang kinaiya sa Dios nga dili siya tawo nga magbakak, Atong tiwason sa pagbasa, “Ang Dios dili tawo busa dili siya mamakak. Dili siya anak sa tawo busa dili mausab ang iyang hunahuna” (Num. 23:19) ug “Magpabilin nga matinud-anon ang Dios bisan pag bakakon ang tanang tawo” (Rom. 3:4). Ang Dios dili tawo apan dili ta makabuot kon ang Dios magpakatawo, “Sa wala pay nagbuhat bisan unsa, ang Pulong diha na. Ang Pulong kauban sa Dios ug ang Pulong Dios… Ang Pulong nahimong tawo ug mipuyo uban kanato” (Jn. 1:1, 14)."},{"objection":"Si Cristo misangpit og laing Dios. Didto sa krus siya mituaw, “Dios ko, Dios ko, nganong gibiyaan mo ako” (Mat. 27:46). Duna ba diay Dios nga biyaan sa Dios? Si Jesus wala gyod moangkon nga siya Dios, “moadto ako sa akong Amahan ug inyong Amahan, sa akong Dios ug inyong Dios” (Jn. 20:17).","response":"Si Cristo matarong, “kita may manlalaban nga si Jesu-Cristo, ang matarong” (1 Jn. 2:1) ug ang Dios misaad nga dili niya biyaan ang matarong niyang katawhan (Sal. 37:28) busa dili mahitabo nga si Jesus biyaan sa Amahan kondili kitang katawhan ang gibiyaan sa Dios tungod sa atong mga sala, “ang inyo hinuong kalapasan maoy nag-ulang kaninyo sa inyong Dios; ang inyong mga sala maoy hinungdan sa iyang pagpahilayo kaninyo” (Isa. 59:2) ug didto sa krus gidala ni Cristo ang atong tingog, “Didto sa krus gidala ni Cristo diha sa iyang lawas ang tanan tang mga sala” (1 Ped. 2:24) busa alang kadto kanato nga si Cristo mituaw niadtong maong mga pulong."},{"objection":"Ang Dios dili mamatay, “Alang sa Hari nga walay kataposan, walay kamatayon ug dili makita, ang bugtong Dios” (1 Tim. 1:17). Apan bahin kang Cristo giingon, “Unya miduko siya ug namatay” (Jn. 19:30). Duna ba diay Dios nga mamatay?","response":"Si Cristo sa iyang tawhanong kahimtang namatay, “Kay si Cristo mismo namatay sa makausa lamang tungod sa atong mga sala” (1 Ped. 3:18) apan sa iyang pagka-Dios dili siya mamatay, “Ako ang pagkabanhaw ug ang kinabuhi” (Jn. 11:25); “Ang pagtulon-an nga among nadawat mao nga ang Cristo dili mamatay, nga ang Cristo magalungtad” (Jn. 12:34); “Si Cristo mao gihapon kagahapon, karon ug sa walay kataposan” (Heb. 13:8)."},{"objection":"Ang Dios nasayod sa tanan, “Ang Labing Halangdon nahibalo sa tanang butang nga mahibaloan” (Sir. 42:18) apan si Cristo miangkon nga wala siya mahibalo sa tanan, “Apan walay nasayod kanus-a moabot kadtong adlawa ug taknaa- bisan ang mga anghel sa langit, ug bisan gani ang Anak, kondili ang Amahan lamang” (Mat. 24:36) busa dili siya Dios.","response":"Si Cristo nasayod sa tanan, “Diha kaniya natago ang tanang bahandi sa kaalam ug kahibalo sa Dios” (Col. 2:3); “si Cristo mao ang gahom ug ang kaalam sa Dios” (1 Cor. 1:24); “Ginoo, nasayod ka sa tanan” (Jn. 16:30). Ang buot ipasabot ni Cristo nga ang maong kahibalo dili ibutyag sa tawo, “Ang mga butang nga gipadayag iya sa tawo apan ang mga butang nga gitago iya sa Dios” (Deut. 29:29). “Ang mga panahon ug mga adlaw gilatid nang daan sa pagbuot sa akong Amahan; dili kamo angay magpakisayod kon kanus-a kini mahitabo” (Buh. 1:7)."},{"objection":"Ang Dios mao ang labaw sa tanan, “imo man ang tanan nga anaa sa langit ug sa yuta, ingon man ang gingharian ug labaw ikaw sa tanan” (1 Kron. 29:11) apan si Jesus miingon, “ang Amahan labaw kay kanako” (Jn. 14:28). Duna ba diay Dios nga malabwan pa og laing Dios?","response":"Ang Amahan labaw kay kaniya bahin sa pagka-Tawo ni Cristo ug mahitungod usab kini sa pagpaubos ni Cristo sa iyang kaugalingon, “Diha niya kanunay ang kinaiya gayod sa Dios, apan wala siya maghunahuna pagpakigtupong sa Dios pinaagi sa kusog. Kondili sa iyang kaugalingong kabubut-on iya kining gibiyaan, ug gisul-ob niya ang kinaiya sa usa ka sulugoon. Natawo siya sama kanato ug nakita siya ingon nga tawo; Nagpaubos siya ug nagmasinugtanon” (Fil 2:6-8). Sa iyang pagka-Dios si Cristo tumbas sa Amahan, “Ang tanan nga iya sa Amahan akoa” (Jn. 16:15); “Kay ingon nga banhawon sa Amahan ang mga patay ug hatagag kinabuhi, banhawon usab sa Anak ug hatagag kinabuhi ang buot niyang banhawon” (Jn. 5:21)."},{"objection":"Ang Dios mao ang ampoan ug ang Manluluwas, “Ako mao ang Ginoo, ug walay laing Manluluwas gawas kanako” (Isa. 43:11) apan didto sa Getsemane si Jesus nag-ampo, “Amahan luwasa ako niining taknaa” (Jn. 12:27). Anaa bay Dios nga mag-ampo ug magpaluwas og laing Dios?","response":"Wala kini maayo pagkabasa tungod kay si Cristo miingon nga andam siya sa pagpasakit ug dili siya mo-ampo nga magpaluwas, “Moingon ba ako, ‘Amahan luwasa ako niining taknaa?’ Dili, kay ang hinungdan sa akong pag-anhi mao ang pagdawat niining takna sa pag-antos” (Jn. 12:27). Si Cristo gipaila nga mao ang Ginoo ug Manluluwas (Luc. 2:11) ug siya ang gipaabot nga gamhanang Dios ug Manluluwas (Tito 2:13)."},{"objection":"Matud ni Jesus, “Ang Dios espiritu” (Jn. 4:24) ug si Jesus gihapon ang nag-ingon, “Hikapa ako ninyo kay ang espiritu walay unod ug mga bukog ingon sa nakita ninyo kanako” (Luc. 24:39) busa dili siya Dios.","response":"Sa iyang pagkatawo si Cristo dunay lawas, “pag-abot sa hustong panahon, gipadala sa Dios ang iyang Anak. Mianhi siya ingon nga anak sa tawhanong inahan” (Gal. 4:4); “Sanglit ang mga anak nakaambit man sa unod ug dugo sa mga ginikanan, si Jesus nahimong sama kanila” (Heb. 2:14) apan sa wala pa siya magpakatawo diha na siya sa kahimtang nga Espiritu, “wala pa gani matawo si Abraham, Ako mao na” (Jn. 8:58); “Ang unang tawo nga si Adan gibuhat nga buhi, apan ang kataposang Adan mao ang Espiritu nga naghatag ug kinabuhi” (1 Cor. 15:45)."},{"objection":"Giingon usab nga si Cristo “ang panganay sa tanang binuhat” (Col 1:15). Busa si Cristo binuhat lang. Ania pa gayod, “Busa ang tanang mga tawo sa Israel kinahanglan nga masayod nga kining maong Jesus nga inyong gilansang sa krus gibuhat sa Dios nga Ginoo ug Mesiyas” (Buh. 2:36).","response":"Ang pag-ingon nga si Cristo ang panganay (Gk. Prototokus = first born) nagpasabot nga siya mao ang gigikanan sa tanang butang, “Kay pinaagi kaniya gibuhat sa Dios ang tanan nga atua sa langit ug ania sa yuta… Gibuhat sa Dios ang tanan pinaagi kaniya ug alang kaniya” (Col. 1:16); “Pinaagi kaniya gibuhat sa Dios ang uniberso… Siya maoy nagkupot sa tibuok uniberso pinaagi sa iyang gamhanang pulong” (Heb. 1:2-3) dili unang gibuhat (Gk. Prototiktes = first created)."}]'::jsonb, '["Isa. 9:6","Luc. 2:11","Isa. 35:4-6","Mat. 11:4-5","Isa. 52:12","1 Cor. 10:4","Jn. 5:19","Jn. 8:23","Jn. 8:58","Jn. 10:30","Jn. 17:5","Jn. 20:28","1 Jn. 5:20","Rom. 9:5","Tito 2:13","Fil. 2:6, 10","Col. 2:9","Heb. 1:8","Isa. 45:5","Jn. 17:3","1 Cor. 8:6","Num 23:19","1 Tim. 2:5","Gal. 4:4","Num. 23:19","Rom. 3:4","Jn. 1:1, 14","Mat. 27:46","Jn. 20:17","1 Jn. 2:1","Isa. 59:2","1 Ped. 2:24","1 Tim. 1:17","Jn. 19:30","1 Ped. 3:18","Jn. 11:25","Jn. 12:34","Heb. 13:8","Sir. 42:18","Mat. 24:36","Col. 2:3","1 Cor. 1:24","Jn. 16:30","Deut. 29:29","Buh. 1:7","1 Kron. 29:11","Jn. 14:28","Fil 2:6-8","Jn. 16:15","Jn. 5:21","Isa. 43:11","Jn. 12:27","Jn. 4:24","Luc. 24:39","Heb. 2:14","1 Cor. 15:45","Col 1:15","Buh. 2:36","Col. 1:16","Heb. 1:2-3"]'::jsonb, '["divinity of christ"]'::jsonb, 'beginner', '[]'::jsonb, 'manual', '2026-07-23T08:13:34.043Z')
